//去除重复的userId 使用mapObject 判断当前数组中是否有对应的userID，来进行去重
const messageObj=timeline.reduce((accumulator,currentValue)=>{
  if(!accumulator.mapObject.hasOwnProperty(currentValue.user_id)){
    accumulator.mapObject[currentValue.user_id] = true;  
    accumulator.unique.push(currentValue);   
  }
  return accumulator;
},{ unique: [], mapObject: {} }).unique;
