// Loop over input items and add a new field called 'myNewField' to the JSON of each one
function validatePhoneNumber(phoneNumbers) {
    const regex = /^1[3-9]\d{9}$/;
    const invalidNumbers = phoneNumbers.filter(e => !regex.test(e));
    return invalidNumbers;
}
jsonData=JSON.parse($('获取审批实例详情').all()[0].json.data.form);
  $input.all()[0].json.phoneNumbers = jsonData.find(el=>el.name==='手机号明细')?.value.map(item => item[0].value);
$input.all()[0].json.channel = jsonData.find(el=>el.name==='流出渠道')?.value;
  $input.all()[0].json.memberName = jsonData.find(el=>el.name==='合作方名称')?.value;
// 调用函数并输出结果
const invalidPhoneNumbers = validatePhoneNumber($input.all()[0].json.phoneNumbers);

//校验所有手机号是否正确
if (invalidPhoneNumbers.length !== 0) {
  $input.all()[0].json.invalidPhoneNumbers=invalidPhoneNumbers;
}
  $input.all()[0].json.trialExirationDate=jsonData.find(el=>el.name==='DateInterval')?.value.end;

return $input.all();

